INSERT INTO `preguntas` VALUES (1,'¿Cuál es el componente de la célula que se encarga de producir la energía necesaria?','Núcleo','Mitocondria','Ribosoma','Citoplasma',2,1),(2,'¿Cuál es el proceso por el cual la célula se divide y reproduce?','Meiosis','Mitosis','Fotosíntesis','Respiración celular',2,1),(3,'¿Qué es el citoplasma en una célula?','El componente que contiene la información genética','El líquido que rodea el núcleo y contiene organelas','La capa externa de la célula','El componente que produce proteínas',2,1),(4,'¿Cuál es la función del ribosoma en la célula?','Producir energía','Sintetizar proteínas','Almacenar información genética','Regular el crecimiento celular',2,1),(5,'¿Qué es lo que la célula utiliza para envolverse y protegerse?','Membrana plasmática','Pared celular','Núcleo','Citoplasma',1,1),(6,'¿Cuál es el planeta más cercano al Sol en nuestro sistema solar?','Venus','Mercurio','La Tierra','Marte',2,2),(7,'¿Cuál es el planeta conocido por su atmósfera densa y misteriosa en la canción?','Júpiter','Saturno','Urano','Venus',4,2),(8,'¿Cuál es el planeta que se describe como el \'guerrero\' en la canción?','Júpiter','Saturno','Marte','Neptuno',3,2),(9,'¿Cuál es el planeta que se caracteriza por tener un eje que se desvía en la canción?','Saturno','Júpiter','Urano','La Tierra',3,2),(10,'¿Cuál es el planeta que se describe como el último en el sistema solar en la canción?','Urano','Neptuno','Saturno','Júpiter',2,2),(11,'¿Cuál es la función de la membrana plasmática en la célula?','Producir energía','Controlar la síntesis de proteínas','Regular lo que entra y sale de la célula','Almacenar información genética',3,3),(12,'¿Cuál es el papel del núcleo en la célula?','Producir energía','Sintetizar proteínas','Controlar la entrada y salida de la célula','Almacenar información genética y controlar la célula',4,3),(13,'¿Dónde se producen los ATP en la célula?','En el núcleo','En la membrana plasmática','En la mitocondria','En los ribosomas',3,3),(14,'¿Cuál es la función de los ribosomas en la célula?','Producir energía','Almacenar información genética','Regular la entrada y salida de la célula','Sintetizar proteínas',4,3),(15,'¿Qué es la célula en términos de la vida y su diversidad?','Un componente de un tejido','Un órgano del cuerpo','La unidad básica de la vida y su diversidad','Un sistema de órganos',3,3),(16,'¿Qué características tienen los números primos según la canción?','Sólo son divisibles por uno y por sí mismos','Sólo son divisibles por números pares','Sólo son divisibles por números impares','Son divisibles por cualquier número',1,4),(17,'¿Cuál es la secuencia de números primos mencionada en la canción?','2, 4, 6, 8','2, 3, 5, 7, 11','1, 3, 5, 7, 9','10, 12, 14, 16',2,4),(18,'¿En qué campo se utilizan los números primos según la canción?','Física','Biología','Criptografía','Química',3,4),(19,'¿Por qué son importantes los números primos según la canción?','Son la base de las matemáticas','Son la base de la física','Son fundamentales para la criptografía y la seguridad','No tienen importancia en las matemáticas',3,4),(20,'¿Qué papel juegan los números primos en la teoría de números según la canción?','Un papel secundario','Un papel importante','Un papel irrelevante','No se menciona',2,4),(21,'¿Cuál es el nombre de la operación matemática que se describe en la canción?','Multiplicación','División','Resta','Suma',2,5),(22,'¿Qué dos componentes se unen en armonía para encontrar el cociente en una división?','Dividendo y resto','Divisor y cociente','Dividendo y divisor','Cociente y resto',3,5),(23,'¿En qué áreas de la vida cotidiana se menciona que la división es fundamental?','Solo en la cocina y el comercio','Solo en la ciencia y el arte','En la cocina, el comercio, la ciencia y el arte','En la política y la economía',3,5),(24,'¿Qué se necesita para dominar la habilidad de dividir según la canción?','Solo práctica','Solo paciencia','Práctica y paciencia','Dedication y falta de pasión',3,5),(25,'¿Qué se conver